class Solution {
    public int[] separateDigits(int[] nums) {
        int[] result = new int[nums.length];
        for (int i = 0; i < nums.length; i++) {
            String str = String.valueOf(nums[i]);
            result[i] = Integer.parseInt(str);
        }
        return result;
    }
}
